namespace sv_60232eae565a496b8612e964814df925.Services;

public class WarehouseInfo
{
    public string Id { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
}

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single user circuit.
/// Fires OnChange when the selection changes so all subscribed components can re-render.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "wh-a", Name = "Warehouse A" },
        new() { Id = "wh-b", Name = "Warehouse B" },
        new() { Id = "wh-c", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId)?.Name ?? "Unknown";

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_60232eae565a496b8612e964814df925.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts on a timer.
/// Notifies all subscribers when new data arrives so they can re-render.
/// Scoped lifetime ensures each user circuit has independent alert state.
/// </summary>
public class InventoryAlertService : IAsyncDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private readonly object _lock = new();

    public int CurrentLowStockCount { get; private set; }

    /// <summary>
    /// Fired from a background thread whenever new alert data arrives.
    /// Subscribers MUST wrap StateHasChanged in InvokeAsync.
    /// </summary>
    public event Action? OnAlertDataChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>Simulates a database query for low-stock items.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component wants polling to be active.
    /// Polling starts on first subscriber and stops when all unsubscribe.
    /// </summary>
    public void StartPolling()
    {
        lock (_lock)
        {
            _subscriberCount++;
            if (_subscriberCount == 1)
            {
                _cts = new CancellationTokenSource();
                _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
                _ = PollLoopAsync(_cts.Token);
            }
        }
    }

    /// <summary>Call when a component no longer needs polling.</summary>
    public void StopPolling()
    {
        lock (_lock)
        {
            _subscriberCount = Math.Max(0, _subscriberCount - 1);
            if (_subscriberCount == 0)
            {
                _cts?.Cancel();
                _timer?.Dispose();
                _timer = null;
                _cts?.Dispose();
                _cts = null;
            }
        }
    }

    /// <summary>Triggers an immediate refresh (e.g., after warehouse change).</summary>
    public async Task RefreshAsync()
    {
        CurrentLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertDataChanged?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire an initial poll immediately so the UI doesn't wait 10 seconds.
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(ct))
                    break;

                CurrentLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
                OnAlertDataChanged?.Invoke();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async void OnWarehouseChanged()
    {
        // When the warehouse changes mid-poll, refresh immediately.
        if (_subscriberCount > 0)
        {
            await RefreshAsync();
        }
    }

    public async ValueTask DisposeAsync()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        await ValueTask.CompletedTask;
    }
}

